import React, { useState, useEffect } from 'react';
import { View, TextInput, Button, Text, AsyncStorage } from 'react-native';

const AuthContext = React.createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);

  useEffect(() => {
    const loadUserData = async () => {
      const userData = await AsyncStorage.getItem('userData');
      if (userData) {
        setUser(JSON.parse(userData));
      }
    };
    loadUserData();
  }, []);

  const signIn = async (token, userData) => {
    setUser(userData);
    await AsyncStorage.setItem('userData', JSON.stringify(userData));
    await AsyncStorage.setItem('token', token);
  };

  const signOut = async () => {
    setUser(null);
    await AsyncStorage.removeItem('userData');
    await AsyncStorage.removeItem('token');
  };

  return (
    <AuthContext.Provider value={{ user, signIn, signOut }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  return React.useContext(AuthContext);
};

const AuthScreen = () => {
  const { signIn } = useAuth();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = async () => {
    const token = 'fakeToken'; // Replace with actual token from API
    const userData = { email }; // Replace with actual user data from API
    await signIn(token, userData);
  };

  return (
    <View>
      <TextInput placeholder="Email" value={email} onChangeText={setEmail} />
      <TextInput placeholder="Password" value={password} onChangeText={setPassword} secureTextEntry />
      <Button title="Login" onPress={handleLogin} />
    </View>
  );
};

const UserScreen = () => {
  const { user, signOut } = useAuth();

  return (
    <View>
      <Text>Welcome, {user.email}</Text>
      <Button title="Logout" onPress={signOut} />
    </View>
  );
};

const App = () => {
  const { user } = useAuth();

  return (
    <View>
      {user ? <UserScreen /> : <AuthScreen />}
    </View>
  );
};

export default () => (
  <AuthProvider>
    <App />
  </AuthProvider>
);